// Dedupe guard — stops the same OPEN incident from being summarized and
// reposted to Slack on every poll. Uses workflow static data (persists across
// production executions). Assumes each incident has a stable unique `id`;
// change idKey below if your incidents API uses a different field.
const idKey = 'id';
const store = $getWorkflowStaticData('global');
const seen = new Set(store.seenIncidentIds || []);

// Normalize input: handle one-item-per-incident, an array in one item, or { incidents: [...] }
let incidents = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) incidents.push(...j);
  else if (Array.isArray(j.incidents)) incidents.push(...j.incidents);
  else incidents.push(j);
}

// Keep only incidents we haven't already posted (no id -> let it through)
const fresh = incidents.filter(inc => {
  const id = inc[idKey];
  if (id === undefined || id === null) return true;
  return !seen.has(id);
});

// Remember what we're about to post; cap to avoid unbounded growth
const newIds = fresh.map(i => i[idKey]).filter(x => x !== undefined && x !== null);
store.seenIncidentIds = [...(store.seenIncidentIds || []), ...newIds].slice(-1000);

console.log('[incident-poller] open:', incidents.length, '| new:', fresh.length, '| suppressed:', incidents.length - fresh.length);

return fresh.map(inc => ({ json: inc }));
